import { describe, expect, it } from 'vitest';
import {
  synthSpectrum,
  demoFrameForBeat,
  demoCycleFrames,
  makeDemoGenerator,
  DEMO_BEAT_SEQUENCE,
  type DemoBeatLabel,
} from './skymesh-serve.mts';
import {
  SKYMESH_SCHEMA_VERSION,
  SKYMESH_CACHED_ANSWER,
  type SkymeshFrame,
} from './skymesh';
import { DEFAULT_WITNESS_OPTS } from './skymesh-witness';
import { PROTOCOL69_EXPECTED_PROJECTION } from '../src/protocol69';

const BANDS = DEFAULT_WITNESS_OPTS.bands; // 64

/** Assert a frame is a structurally-valid gnosis.skymesh.v1 frame. */
function assertValidFrame(frame: SkymeshFrame): void {
  expect(Object.keys(frame).sort()).toEqual(
    ['airGap', 'match', 'schemaVersion', 'stations'].sort(),
  );
  expect(frame.schemaVersion).toBe(SKYMESH_SCHEMA_VERSION);
  expect(frame.airGap.linkBetweenStations).toBe(false);
  expect(typeof frame.airGap.proof).toBe('string');
  expect(frame.airGap.proof.length).toBeGreaterThan(0);
  expect(typeof frame.match).toBe('boolean');
  expect(frame.stations).toHaveLength(2);
  for (const s of frame.stations) {
    expect(Object.keys(s).sort()).toEqual(
      [
        'geodesicLength',
        'id',
        'projection',
        'spectrum',
        'state',
        'token',
        'witness',
        'witnessLocked',
      ].sort(),
    );
    expect(typeof s.id).toBe('string');
    expect(typeof s.witness).toBe('number');
    expect(typeof s.witnessLocked).toBe('boolean');
    expect(typeof s.projection).toBe('number');
    expect(typeof s.geodesicLength).toBe('number');
    expect(s.token === null || typeof s.token === 'string').toBe(true);
    expect(['LISTENING', 'WITNESS_LOCKED', 'TELEPORTED', 'DENIED']).toContain(s.state);
    // The web app renders 64-band spectra.
    expect(s.spectrum).toHaveLength(BANDS);
    for (const v of s.spectrum) {
      expect(Number.isFinite(v)).toBe(true);
      expect(v).toBeGreaterThanOrEqual(0);
    }
  }
}

describe('synthSpectrum', () => {
  it('produces a normalized 64-band shape that sums to ~1', () => {
    const spec = synthSpectrum({ phase: 0.3, lockProgress: 0, carrierBand: 30 });
    expect(spec).toHaveLength(BANDS);
    const sum = spec.reduce((a, b) => a + b, 0);
    expect(sum).toBeCloseTo(1, 6);
    for (const v of spec) expect(v).toBeGreaterThanOrEqual(0);
  });

  it('a locked carrier dominates its band; an unlocked floor does not', () => {
    const floor = synthSpectrum({ phase: 0, lockProgress: 0, carrierBand: 30 });
    const locked = synthSpectrum({ phase: 0, lockProgress: 1, carrierBand: 30 });
    // The carrier band is the max of the locked spectrum...
    const lockedMax = Math.max(...locked);
    expect(locked[30]).toBe(lockedMax);
    // ...and is far stronger than the same band when unlocked.
    expect(locked[30]!).toBeGreaterThan(floor[30]! * 3);
  });

  it('phase moves the noise floor (successive ticks animate)', () => {
    const a = synthSpectrum({ phase: 0, lockProgress: 0, carrierBand: 30 });
    const b = synthSpectrum({ phase: 1.0, lockProgress: 0, carrierBand: 30 });
    expect(a).not.toEqual(b);
  });
});

describe('demoFrameForBeat', () => {
  it('every beat in the cycle yields a valid gnosis.skymesh.v1 frame', () => {
    for (const beat of DEMO_BEAT_SEQUENCE) {
      assertValidFrame(demoFrameForBeat(beat, 0));
    }
  });

  it('LISTENING: no station locked, no token, match false', () => {
    const f = demoFrameForBeat('LISTENING', 0);
    expect(f.match).toBe(false);
    expect(f.stations.every((s) => s.state === 'LISTENING')).toBe(true);
    expect(f.stations.every((s) => s.token === null)).toBe(true);
    expect(f.stations.every((s) => s.witnessLocked === false)).toBe(true);
  });

  it('WITNESS_LOCKING / WITNESS_LOCKED: locked but not yet teleported, no token', () => {
    for (const beat of ['WITNESS_LOCKING', 'WITNESS_LOCKED'] as DemoBeatLabel[]) {
      const f = demoFrameForBeat(beat, 0);
      expect(f.match).toBe(false);
      expect(f.stations.every((s) => s.witnessLocked === true)).toBe(true);
      expect(f.stations.every((s) => s.state === 'WITNESS_LOCKED')).toBe(true);
      expect(f.stations.every((s) => s.token === null)).toBe(true);
    }
  });

  it('TELEPORTED: both stations teleported, equal tokens, match true', () => {
    const f = demoFrameForBeat('TELEPORTED', 0);
    expect(f.match).toBe(true);
    expect(f.stations.every((s) => s.state === 'TELEPORTED')).toBe(true);
    expect(f.stations.every((s) => s.token === SKYMESH_CACHED_ANSWER)).toBe(true);
    expect(f.stations.every((s) => s.projection === PROTOCOL69_EXPECTED_PROJECTION)).toBe(true);
  });

  it('DENIED: B forged the key -> A teleports, B DENIED, match false', () => {
    const f = demoFrameForBeat('DENIED', 0);
    expect(f.match).toBe(false);
    expect(f.stations[0]!.state).toBe('TELEPORTED');
    expect(f.stations[1]!.state).toBe('DENIED');
    expect(f.stations[1]!.token).toBeNull();
    expect(f.stations[1]!.projection).not.toBe(PROTOCOL69_EXPECTED_PROJECTION);
  });

  it('MISS: different skies -> witnesses disagree, both denied, match false', () => {
    const f = demoFrameForBeat('MISS', 0);
    expect(f.match).toBe(false);
    expect(f.stations.every((s) => s.token === null)).toBe(true);
    expect(f.stations.every((s) => s.state === 'DENIED')).toBe(true);
  });
});

describe('demo cycle progression', () => {
  it('the six-beat cycle reaches TELEPORTED(match true) and DENIED + MISS(match false)', () => {
    const frames = demoCycleFrames(0);
    expect(frames).toHaveLength(DEMO_BEAT_SEQUENCE.length);
    frames.forEach(assertValidFrame);

    const teleportIdx = DEMO_BEAT_SEQUENCE.indexOf('TELEPORTED');
    const deniedIdx = DEMO_BEAT_SEQUENCE.indexOf('DENIED');
    const missIdx = DEMO_BEAT_SEQUENCE.indexOf('MISS');

    expect(frames[teleportIdx]!.match).toBe(true);
    expect(frames[deniedIdx]!.match).toBe(false);
    expect(frames[missIdx]!.match).toBe(false);

    // At least one beat teleports the cached answer.
    const anyTeleport = frames.some(
      (f) => f.stations.every((s) => s.state === 'TELEPORTED' && s.token === SKYMESH_CACHED_ANSWER),
    );
    expect(anyTeleport).toBe(true);
  });
});

describe('makeDemoGenerator', () => {
  it('advances through the whole cycle and every emitted frame is valid', () => {
    const gen = makeDemoGenerator(2); // hold each beat for 2 ticks
    const seenMatchTrue = new Set<boolean>();
    const seenStates = new Set<string>();
    // 2 ticks/beat * 6 beats = 12 frames for one full cycle.
    for (let i = 0; i < 12; i++) {
      const f = gen();
      assertValidFrame(f);
      seenMatchTrue.add(f.match);
      for (const s of f.stations) seenStates.add(s.state);
    }
    // Over a full cycle we must have seen both a match and a non-match...
    expect(seenMatchTrue.has(true)).toBe(true);
    expect(seenMatchTrue.has(false)).toBe(true);
    // ...and all four schema states.
    expect(seenStates.has('LISTENING')).toBe(true);
    expect(seenStates.has('WITNESS_LOCKED')).toBe(true);
    expect(seenStates.has('TELEPORTED')).toBe(true);
    expect(seenStates.has('DENIED')).toBe(true);
  });
});
